b = {'y': 5, 'z': 3}
out = dict(a)
for k, v in b.items():
    out[k] = out.get(k, 0) + v
print(out)  # {'x': 1, 'y': 7, 'z': 3}

solution:
def parse(s):
    d = {}
    if s.strip():
        for pair in s.split(','):
            k, v = pair.split(':')
            d[k.strip()] = int(v)
    return d

d1 = parse(input())
d2 = parse(input())
merged = dict(d1)
for k, v in d2.items():
    merged[k] = merged.get(k, 0) + v
for k in sorted(merged):
    print(f'{k}:{merged[k]}')
